import * as React from "react";

export interface TdCardProps {
  image?: { src: string; alt: string };
  eyebrow?: string;
  headline: string;
  body?: string;
  cta?: { label: string; href: string };
  className?: string;
}

export function TdCard({ image, eyebrow, headline, body, cta, className = "" }: TdCardProps) {
  return (
    <article
      className={`group flex h-full flex-col overflow-hidden rounded-xl border bg-white shadow-sm transition-shadow hover:shadow-md ${className}`.trim()}
      style={{ borderColor: "var(--td-border, rgba(15,23,42,0.08))" }}
    >
      {image ? (
        <div className="aspect-[16/10] w-full overflow-hidden bg-slate-100">
          <img
            src={image.src}
            alt={image.alt}
            className="h-full w-full object-cover transition-transform duration-500 group-hover:scale-[1.03]"
          />
        </div>
      ) : null}
      <div className="flex flex-1 flex-col gap-3 p-6">
        {eyebrow ? (
          <span
            className="text-xs font-semibold uppercase tracking-[0.18em]"
            style={{ color: "var(--td-secondary, #234F98)" }}
          >
            {eyebrow}
          </span>
        ) : null}
        <h3 className="text-xl font-semibold leading-snug tracking-tight text-slate-900">
          {headline}
        </h3>
        {body ? <p className="text-sm leading-relaxed text-slate-600">{body}</p> : null}
        {cta ? (
          <a
            href={cta.href}
            className="mt-auto inline-flex items-center gap-1 text-sm font-medium hover:underline"
            style={{ color: "var(--td-primary, #2E6554)" }}
          >
            {cta.label} <span aria-hidden>{"->"}</span>
          </a>
        ) : null}
      </div>
    </article>
  );
}

export default TdCard;
